 1→import React, { useState } from 'react';
 2→import { motion } from 'framer-motion';
 3→import useAnalyticsData from './useAnalyticsData';
 4→import TimeRangeSelector from './TimeRangeSelector';
 5→import AnalyticsSummary from './AnalyticsSummary';
 6→import ViewsChart from './ViewsChart';
 7→import ReactionsChart from './ReactionsChart';
 8→import ReactionBreakdown from './ReactionBreakdown';
 9→import TopPosts from './TopPosts';
10→import PublishingFrequency from './PublishingFrequency';
11→import './AnalyticsDashboard.css';
12→
13→const AnalyticsDashboard = () => {
14→    const [range, setRange] = useState('30d');
15→    const { data, isLoading, isError } = useAnalyticsData(range);
16→
17→    const analytics = data?.analytics;
18→
19→    if (isLoading) {
20→        return (
21→            <div className="analytics-dashboard">
22→                <div className="analytics-header">
23→                    <h1 className="analytics-title">Analytics</h1>
24→                </div>
25→                <div className="analytics-loading">
26→                    <div className="analytics-loading-spinner" />
27→                    <p className="analytics-loading-text">Crunching your numbers...</p>
28→                </div>
29→            </div>
30→        );
31→    }
32→
33→    if (isError) {
34→        return (
35→            <div className="analytics-dashboard">
36→                <div className="analytics-header">
37→                    <h1 className="analytics-title">Analytics</h1>
38→                </div>
39→                <div className="analytics-empty">
40→                    <p className="analytics-empty-text">Something went wrong loading your analytics. Try again later.</p>
41→                </div>
42→            </div>
43→        );
44→    }
45→
46→    const isEmpty = !analytics?.summary?.total_posts;
47→
48→    return (
49→        <motion.div
50→            className="analytics-dashboard"
51→            initial={{ opacity: 0, y: 10 }}
52→            animate={{ opacity: 1, y: 0 }}
53→            transition={{ duration: 0.35, ease: 'easeOut' }}
54→        >
55→            <div className="analytics-header">
56→                <div className="analytics-header-left">
57→                    <h1 className="analytics-title">Analytics</h1>
58→                    {analytics?.streak?.current_streak > 0 && (
59→                        <span className="analytics-streak-badge">
60→                            {analytics.streak.current_streak} day streak
61→                        </span>
62→                    )}
63→                </div>
64→                <TimeRangeSelector value={range} onChange={setRange} />
65→            </div>
66→
67→            {isEmpty ? (
68→                <div className="analytics-empty">
69→                    <p className="analytics-empty-heading">No data yet</p>
70→                    <p className="analytics-empty-text">
71→                        Start publishing to see your writing analytics here.
72→                    </p>
73→                </div>
74→            ) : (
75→                <>
76→                    <AnalyticsSummary summary={analytics.summary} />
77→
78→                    <div className="analytics-charts-grid">
79→                        <ViewsChart data={analytics.views_series} />
80→                        <ReactionsChart data={analytics.reactions_series} />
81→                    </div>
82→
83→                    <div className="analytics-charts-grid">
84→                        <ReactionBreakdown data={analytics.reaction_breakdown} />
85→                        <PublishingFrequency data={analytics.publishing_frequency} />
86→                    </div>
87→
88→                    <TopPosts data={analytics.top_posts} />
89→                </>
90→            )}
91→        </motion.div>
92→    );
93→};
94→
95→export default AnalyticsDashboard;
