 3→
 4→const VALID_RANGES = ['7d', '30d', '90d', 'all'];
 5→
 6→export const getWriterAnalyticsController = asyncHandler(async (req, res) => {
 7→    const userId = req.userId;
 8→    const range = req.query.range || '30d';
 9→
10→    if (!VALID_RANGES.includes(range)) {
11→        return res.status(400).json({ error: 'Invalid range. Use 7d, 30d, 90d, or all' });
12→    }
13→
14→    const analytics = await getWriterAnalyticsService(userId, range);
15→    return res.status(200).json({ analytics });
16→});
