23→                        initial={{ opacity: 0, x: -10 }}
24→                        animate={{ opacity: 1, x: 0 }}
25→                        transition={{ duration: 0.25, delay: i * 0.05 }}
26→                    >
27→                        <span className="analytics-breakdown-emoji">{getReactionEmoji(item.type)}</span>
28→                        <span className="analytics-breakdown-label">{REACTION_MAP[item.type]?.label}</span>
29→                        <div className="analytics-breakdown-bar-track">
30→                            <motion.div
31→                                className="analytics-breakdown-bar-fill"
32→                                initial={{ width: 0 }}
33→                                animate={{ width: `${(item.count / maxCount) * 100}%` }}
34→                                transition={{ duration: 0.5, delay: 0.15 + i * 0.05 }}
35→                            />
36→                        </div>
37→                        <span className="analytics-breakdown-count">{item.count}</span>
38→                    </motion.div>
39→                ))}
40→            </div>
41→        </div>
42→    );
43→};
44→
45→export default ReactionBreakdown;
46→

