import React from 'react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const formatDate = (dateStr) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
};

const CustomTooltip = ({ active, payload, label }) => {
    if (!active || !payload?.length) return null;
    return (
        <div className="analytics-chart-tooltip">
            <span className="analytics-tooltip-date">{formatDate(label)}</span>
            <span className="analytics-tooltip-value">{payload[0].value} views</span>
        </div>
    );
};

const ViewsChart = ({ data }) => {
    if (!data?.length) return null;

    return (
        <div className="analytics-chart-card">
            <h3 className="analytics-chart-title">Views</h3>
            <div className="analytics-chart-container">
                <ResponsiveContainer width="100%" height={220}>
                    <AreaChart data={data} margin={{ top: 8, right: 8, left: -20, bottom: 0 }}>
                        <defs>
                            <linearGradient id="viewsGradient" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="var(--accent-amber, #f59e0b)" stopOpacity={0.3} />
                                <stop offset="95%" stopColor="var(--accent-amber, #f59e0b)" stopOpacity={0} />
                            </linearGradient>
                        </defs>
                        <XAxis
                            dataKey="date"
                            tickFormatter={formatDate}
                            tick={{ fontSize: 11, fill: 'var(--text-muted, #9ca3af)' }}
                            axisLine={false}
                            tickLine={false}
                            interval="preserveStartEnd"
                        />
                        <YAxis
                            tick={{ fontSize: 11, fill: 'var(--text-muted, #9ca3af)' }}
                            axisLine={false}
                            tickLine={false}
                            allowDecimals={false}
                        />
                        <Tooltip content={<CustomTooltip />} />
                        <Area
                            type="monotone"
                            dataKey="count"
                            stroke="var(--accent-amber, #f59e0b)"
                            strokeWidth={2}
                            fill="url(#viewsGradient)"
                        />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
};

export default ViewsChart;

